#!/usr/bin/env node
/**
 * Agentic NFL REGULAR Props Runner (NO TDs)
 * 
 * Runs the agentic pipeline for NFL player props (yards, receptions, attempts only).
 * DOES NOT include TD props - use run-agentic-nfl-td.js for those.
 * 
 * Use this script when:
 * - TD picks have already been generated by run-agentic-nfl-td.js
 * - You only want to re-run/refresh regular props without touching TDs
 * 
 * Usage:
 *   node scripts/run-agentic-nfl-props-regular.js                    # Preview only
 *   node scripts/run-agentic-nfl-props-regular.js --store=1          # Store to Supabase
 *   node scripts/run-agentic-nfl-props-regular.js --matchup=Bills    # Filter matchup
 *   node scripts/run-agentic-nfl-props-regular.js --limit=3          # Limit games
 */
import { runAgenticPropsCli } from './run-agentic-props-cli.js';
import { buildNflPropsAgenticContext } from '../src/services/agentic/nflPropsAgenticContext.js';

runAgenticPropsCli({
  sportKey: 'americanfootball_nfl',
  leagueLabel: 'NFL',
  buildContext: buildNflPropsAgenticContext,
  windowHours: 24 * 7,     // NFL is weekly
  propsPerGame: 3,         // Regular props only: 3 picks per game (yards, receptions, etc.)
  limitDefault: 16,        // Max 16 games
  useESTDayFiltering: true,
  regularOnly: true        // KEY: Only generate regular props, NO TDs
})
  .then(() => process.exit(0))
  .catch((error) => {
    console.error('Agentic NFL Regular Props runner crashed:', error);
    process.exit(1);
  });
